import { defineConfig, type Plugin } from "vite";
import react from "@vitejs/plugin-react-swc";
import path from "path";
import { componentTagger } from "lovable-tagger";

/**
 * Adds <link rel="preload" as="style"> for CSS files generated by Vite,
 * so the browser starts fetching CSS before it encounters the <link rel="stylesheet">.
 */
function cssPreloadPlugin(): Plugin {
  return {
    name: "css-preload",
    enforce: "post",
    transformIndexHtml(html) {
      const cssLinks = [...html.matchAll(/<link[^>]+rel="stylesheet"[^>]+href="([^"]+\.css)"[^>]*>/g)];
      if (!cssLinks.length) return html;

      const preloadTags = cssLinks
        .map(([, href]) => `<link rel="preload" href="${href}" as="style">`)
        .join("\n    ");

      return html.replace("</head>", `    ${preloadTags}\n  </head>`);
    },
  };
}

// https://vitejs.dev/config/
export default defineConfig(({ mode }) => ({
  server: {
    host: "::",
    port: 8080,
    hmr: {
      overlay: false,
    },
  },
  plugins: [react(), cssPreloadPlugin(), mode === "development" && componentTagger()].filter(Boolean),
  resolve: {
    alias: {
      "@": path.resolve(__dirname, "./src"),
    },
  },
  build: {
    rollupOptions: {
      output: {
        manualChunks: {
          "vendor-react": ["react", "react-dom"],
          "vendor-router": ["react-router-dom"],
          "vendor-query": ["@tanstack/react-query"],
        },
      },
    },
    // Target modern browsers to avoid legacy polyfills
    target: "es2020",
    // Reduce CSS size
    cssMinify: true,
  },
}));